<script>
    function toggleLanguageDropdown(e) {
        var target = e.target,
            languageDropdown = MG_Utils.hasClass(target, 'languageSelected') ? target : MG_Utils.closest(target, '.languageSelected'),
            languagesList = document.querySelector('#modalWrapMTubes .languages.dropdownWrapper');

        if (languageDropdown) {
            var isExpanded = MG_Utils.hasClass(languageDropdown, 'active');
            MG_Utils.toggleClass(languageDropdown, 'active');
            MG_Utils.toggleClass(languagesList, 'displayBlock');
            languageDropdown.setAttribute('aria-expanded', !isExpanded);
        }
    }

    function setupAgeDisclaimerAccessibility(modal) {
        function getFocusableElements() {
            return Array.from(modal.querySelectorAll(focusableSelectors)).filter(function(el) {
                return el.offsetParent !== null && getComputedStyle(el).visibility !== 'hidden';
            });
        }

        function trapFocus(e) {
            if (e.key !== 'Tab') return;

            var focusableElements = getFocusableElements();
            if (focusableElements.length === 0) return;

            var firstElement = focusableElements[0];
            var lastElement = focusableElements[focusableElements.length - 1];

            if (e.shiftKey) {
                if (document.activeElement === firstElement) {
                    e.preventDefault();
                    lastElement.focus();
                }
            } else {
                if (document.activeElement === lastElement) {
                    e.preventDefault();
                    firstElement.focus();
                }
            }
        }

        function handleKeydown(e) {
            trapFocus(e);

            var languageDropdown = modal.querySelector('.languageSelected');
            if (languageDropdown && document.activeElement === languageDropdown) {
                if (e.key === 'Enter' || e.key === ' ') {
                    e.preventDefault();
                    languageDropdown.click();
                }
            }
        }

        modal.addEventListener('keydown', handleKeydown);

        function setInitialFocus() {
            var firstFocusable = getFocusableElements()[0];
            if (firstFocusable) {
                firstFocusable.focus();
            } else if (modal.offsetParent !== null) {
                modal.focus();
            } else {
                requestAnimationFrame(setInitialFocus);
            }
        }
        requestAnimationFrame(setInitialFocus);
    }

    function triggerGA4Event(eventType, originUrl, originPart, itemId, originVariation) {
        let ga4Obj = {'event': eventType};
        if (originPart) ga4Obj.origin = originPart;
        if (originUrl) ga4Obj.origin_url = originUrl;
        if (itemId) ga4Obj.origin_item_id = itemId;
        if (originVariation) ga4Obj.origin_item_variation = originVariation;
        window.dataLayer.push(ga4Obj);
    }

</script>

