                event.preventDefault();
                if (typeof MG_Utils !== "undefined") {
                    MG_Utils.ajaxCall({
                        url: telemetryDomain + '/_i?type=event&event=' + eventType + originPartCombined + encodedUrl + clickedElement + originVariation,
